// NOTE These functions are implemented using assembly because they use a custom
// calling convention which can't be implemented using a normal Rust function

// NOTE These functions are never mangled as they are not tested against compiler-rt

intrinsics! {
    #[unsafe(naked)]
    #[cfg(any(all(windows, target_env = "gnu"), target_os = "uefi"))]
    pub unsafe extern "custom" fn __chkstk() {
        core::arch::naked_asm!(
            "jmp {}", // Jump to __alloca since fallthrough may be unreliable"
            sym crate::x86::_alloca::_alloca,
        );
    }

    #[unsafe(naked)]
    #[cfg(any(all(windows, target_env = "gnu"), target_os = "uefi"))]
    pub unsafe extern "custom" fn _alloca() {
        // __chkstk and _alloca are the same function
        core::arch::naked_asm!(
            "push   ecx",
            "cmp    eax, 0x1000",
            "lea    ecx, [esp + 8]", // esp before calling this routine -> ecx
            "jb     3f",
            "2:",
            "sub    ecx, 0x1000",
            "test   [ecx], ecx",
            "sub    eax, 0x1000",
            "cmp    eax, 0x1000",
            "ja     2b",
            "3:",
            "sub    ecx, eax",
            "test   [ecx], ecx",
            "lea    eax, [esp + 4]", // load pointer to the return address into eax
            "mov    esp, ecx",       // install the new top of stack pointer into esp
            "mov    ecx, [eax - 4]", // restore ecx
            "push   [eax]",          // push return address onto the stack
            "sub    eax, esp",       // restore the original value in eax
            "ret",
        );
    }
}

use crate::{Diagnostic, DiagnosticCode, DiagnosticsContext};

// Diagnostic: infer-vars-not-allowed
//
// This diagnostic is triggered when `_` is used where type
// inference is not allowed.
pub(crate) fn infer_vars_not_allowed(
    ctx: &DiagnosticsContext<'_, '_>,
    d: &hir::InferVarsNotAllowed,
) -> Diagnostic {
    Diagnostic::new_with_syntax_node_ptr(
        ctx,
        DiagnosticCode::RustcHardError("E0121"),
        "the type placeholder `_` is not allowed within types on item signatures",
        d.node,
    )
}
#[cfg(test)]
mod tests {
    use crate::tests::check_diagnostics;
    #[test]
    fn type_alias() {
        check_diagnostics(
            r#"
type Foo = _;
        // ^ error: the type placeholder `_` is not allowed within types on item signatures
        "#,
        );
    }
    #[test]
    fn const_item() {
        check_diagnostics(
            r#"
const X: _ = 0;
      // ^ error: the type placeholder `_` is not allowed within types on item signatures
        "#,
        );
    }

    #[test]
    fn static_item() {
        check_diagnostics(
            r#"
static Y: _ = 0;
       // ^ error: the type placeholder `_` is not allowed within types on item signatures
        "#,
        );
    }
}
